78:     /**
79:      * Write all records to the given channel (including partial records).
80:      * @param channel The channel to write to
81:      * @return The number of bytes written
82:      * @throws IOException For any IO errors writing to the channel
83:      */
84:     public int writeFullyTo(GatheringByteChannel channel) throws IOException {
85:         buffer.mark();
86:         int written = 0;
87:         while (written < sizeInBytes())
88:             written += channel.write(buffer);
89:         buffer.reset();
90:         return written;
91:     }
