216:     private static BatchFilterResult filterBatch(RecordBatch batch,
217:                                                  BufferSupplier decompressionBufferSupplier,
218:                                                  FilterResult filterResult,
219:                                                  RecordFilter filter) {
220:         try (final CloseableIterator<Record> iterator = batch.streamingIterator(decompressionBufferSupplier)) {
221:             long maxOffset = -1;
222:             boolean containsTombstones = false;
223:             // Convert records with old record versions
224:             boolean writeOriginalBatch = batch.magic() >= RecordBatch.CURRENT_MAGIC_VALUE;
225:             List<Record> retainedRecords = new ArrayList<>();
226:             while (iterator.hasNext()) {
227:                 Record record = iterator.next();
228:                 filterResult.messagesRead += 1;
229: 
230:                 if (filter.shouldRetainRecord(batch, record)) {
231:                     if (record.offset() > maxOffset)
232:                         maxOffset = record.offset();
233: 
234:                     retainedRecords.add(record);
235: 
236:                     if (!record.hasValue()) {
237:                         containsTombstones = true;
238:                     }
239:                 } else {
240:                     writeOriginalBatch = false;
241:                 }
242:             }
243:             return new BatchFilterResult(retainedRecords, writeOriginalBatch, containsTombstones, maxOffset);
244:         }
245:     }
