299:     private CloseableIterator<Record> uncompressedIterator() {
300:         final ByteBuffer buffer = this.buffer.duplicate();
301:         buffer.position(RECORDS_OFFSET);
302:         return new RecordIterator() {
303:             @Override
304:             protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
305:                 try {
306:                     return DefaultRecord.readFrom(buffer, baseOffset, baseTimestamp, baseSequence, logAppendTime);
307:                 } catch (BufferUnderflowException e) {
